            margin: 60px;
            background: linear-gradient(135deg, #dbeafe, #e0f2fe);
            padding: 80px 20px;
            border-radius: 12px;
            text-align: center;
        }
        .card {
            background: white;
            width: 440px;
            margin: 30px auto;
            padding: 40px;
            border-radius: 12px;
            box-shadow: 0 10px 25px rgba(0,0,0,0.08);
        }
        h2 { margin-bottom: 15px; color: #0f172a; }
        p { color: #475569; margin-bottom: 18px; }
        .field {
            width: 100%;
            padding: 12px;
            border: 1px solid #cbd5e1;
            border-radius: 8px;
            margin-bottom: 10px;
        }
        button {
            width: 100%;
            padding: 12px;
            border: none;
            border-radius: 8px;
            font-weight: 600;
            cursor: pointer;
            transition: 0.2s;
        }
        .stack-buttons { display: flex; flex-direction: column; gap: 12px; align-items: stretch; margin-top: 12px; }
        .btn-primary { background: #2563eb; color: white; }
        .btn-primary:hover { background: #1d4ed8; }
        .btn-secondary {
            background: #64748b;
            color: white;
            display: block;
            width: 100%;
            padding: 12px;
            text-align: center;
            border-radius: 8px;
            box-sizing: border-box;
        }
        .btn-secondary:hover { background: #475569; }
        .btn-dashboard {
            background: #10b981;
            color: white;
            display: block;
            width: 100%;
            padding: 12px;
            text-align: center;
            border-radius: 8px;
            box-sizing: border-box;
        }
        .btn-dashboard:hover { background: #059669; }
        .no-decoration { text-decoration: none; display: block; }
        .wallet-box {
            display: flex;
            align-items: center;
            justify-content: space-between;
            gap: 10px;
            background: #f8fafc;
            border: 1px solid #cbd5e1;
            border-radius: 8px;
