<body>


<div class="navbar">
    <div class="logo">
        <div class="logo-box">&#10003;</div>
        BlockVote
    </div>
    <div class="nav-links">

            <a href="/">Home</a>
            <a href="/register/">Voter</a>
            <a href="/results/">Results</a>

    </div>
</div>


<div class="hero">
    <div class="card">
        <h2>Voter Registration</h2>
        <p>Register with email and password, then generate a wallet address.</p>

        <form method="POST">
            <input type="hidden" name="csrfmiddlewaretoken" value="kkoIlY2u68D6gTn4FNdh86LgmYPOEOhwfuMESQEf6mkFj0g2h742SsUZUwjZP9cg">



            <input class="field" type="email" name="email" placeholder="Enter Email" value="" required>
            <input class="field" type="password" name="password" placeholder="Enter Password" required>



            <div class="stack-buttons">
                <button type="submit" class="btn-primary">Register and Generate Wallet Address</button>
                <a href="/voter-login/" class="no-decoration btn-secondary">Already Registered? Login</a>

                    <a href="/voter-login/" class="no-decoration btn-dashboard">Go to Dashboard</a>

            </div>
        </form>
    </div>
</div>

<script>
    function copyWallet() {
        const walletEl = document.getElementById('walletAddress');
        const copyMessage = document.getElementById('copyMessage');
        if (!walletEl) return;

        const wallet = walletEl.textContent.trim();
        navigator.clipboard.writeText(wallet).then(function () {
            if (copyMessage) {
                copyMessage.style.display = 'block';
            }
        });
    }
</script>

</body>
</html>

