            display: flex;
            align-items: center;
            gap: 8px;
            cursor: pointer;
            font-size: 18px;
            font-weight: 500;
        }
        .user-type-label input[type="radio"] {
            width: auto;
            margin: 0;
            cursor: pointer;
        }
        .admin-link {
            text-align: center;
            margin-top: 15px;
        }
        .admin-link a {
            color: #2563eb;
            text-decoration: none;
            font-size: 16px;
        }
        .admin-link a:hover {
            text-decoration: underline;
        }
        .register-link {
            text-align: center;
            margin-top: 15px;
            color: #475569;
        }
        .register-link a {
            color: #2563eb;
            text-decoration: none;
            font-weight: 500;
        }
        .register-link a:hover {
            text-decoration: underline;
        }
    </style>
</head>
<body>


<div class="navbar">
    <div class="logo">BlockVote</div>
    <div class="nav-links">
        <a href="/">Home</a>
        <a href="/register/">Voter</a>
        <a href="/results/">Results</a>

    </div>
</div>


<div class="container">
    <div class="card">
        <h2>Login</h2>



        <form method="POST" id="loginForm">
            <input type="hidden" name="csrfmiddlewaretoken" value="hgroOa1voxxra6f2ysKKwp66MlmNf6fKcqPkl2DgoLe0dd80aMBvgLfPkTQYqrau">

            <div class="user-type-selector">
                <label class="user-type-label">
                    <input type="radio" name="user_type" value="voter" checked>
                    Voter
                </label>
                <label class="user-type-label">
                    <input type="radio" name="user_type" value="admin">
                    Admin
                </label>
            </div>

            <input type="email" name="email" placeholder="Enter Email" required>
            <input type="password" name="password" placeholder="Enter Password" required>
            <input type="text" name="wallet" placeholder="Enter Wallet Address" required>
            <button type="submit">Login</button>

            <div class="register-link">
                Don't have an account? <a href="/register/">Register here</a>
            </div>
        </form>
    </div>
</div>

<script>
    document.getElementById('loginForm').addEventListener('submit', function(e) {
        const userType = document.querySelector('input[name="user_type"]:checked').value;

        if (userType === 'admin') {
            e.preventDefault();
            window.location.href = '/admin-login/';
        }
    });
</script>

</body>
</html>

